+    CONFLICT: 'CONFLICT', DO: 'DO', NOTHING: 'NOTHING', EXCLUDED: 'EXCLUDED', USING: 'USING',
+    // EXPLAIN
+    EXPLAIN: 'EXPLAIN', ANALYZE: 'ANALYZE',
